(window.webpackJsonp=window.webpackJsonp||[]).push([[102],{729:function(n,r){n.exports="\x3c!-- \r\ntitle: 03-Arduino数字IO\r\nsort: \r\n--\x3e \r\n# Arduino数字IO\r\n\r\n## 数字信号\r\n\r\n- 配置引脚模式\r\n\r\n  `pinMode(pin, mode);`\r\n\r\n  > INPUT[0]\t输入模式\r\n  >\r\n  > OUTPUT[1]\t输出模式\r\n  >\r\n  > INPUT_PULLUP\t输入上拉模式\r\n\r\n- 控制引脚输出\r\n\r\n  `digitalWrite(pin, value);`\r\n\r\n  > LOW[0]\t\t低电平\r\n  >\r\n  > HIGH[1]\t\t高电平\r\n\r\n- 读取引脚输入\r\n\r\n  `digitalRead(pin);`\r\n\r\n## 流水灯\r\n\r\n```c\r\nvoid setup() \r\n{\r\n  // 初始化I/O口\r\n  for(int i=2;i<8;i++)\r\n    pinMode(i,OUTPUT);\r\n}\r\n \r\nvoid loop() \r\n{\r\n  // 从引脚2到引脚6，逐个点亮LED，等待1秒再熄灭LED\r\n  for(int i=2;i<7;i+=2)\r\n  {\r\n    digitalWrite(i,HIGH);\r\n    delay(100);\r\n    digitalWrite(i,LOW);   \r\n  }\r\n  // 从引脚7到引脚3，逐个点亮LED，等待1秒再熄灭LED\r\n  for(int i=7;i>2;i-=2)\r\n  {\r\n    digitalWrite(i,HIGH);\r\n    delay(100);\r\n    digitalWrite(i,LOW);   \r\n  } \r\n}\r\n```\r\n\r\n"}}]);